import logging
import json
import os
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, CloudEvent

# --- Configuration (replace with your actual resource names/URLs) ---
# Blob Storage
BLOB_ACCOUNT_URL = os.environ.get('BLOB_ACCOUNT_URL')  # e.g., "https://<your_storage_account_name>.blob.core.windows.net"
BLOB_CONTAINER_NAME = os.environ.get('BLOB_CONTAINER_NAME') # e.g., "input-files"

# Cosmos DB
COSMOS_DB_ENDPOINT = os.environ.get('COSMOS_DB_ENDPOINT') # e.g., "https://<your_cosmosdb_account_name>.documents.azure.com:443/"
COSMOS_DB_DATABASE_NAME = os.environ.get('COSMOS_DB_DATABASE_NAME') # e.g., "FileProcessingDB"
COSMOS_DB_CONTAINER_NAME = os.environ.get('COSMOS_DB_CONTAINER_NAME') # e.g., "ProcessedFiles"

# Event Grid
EVENT_GRID_TOPIC_ENDPOINT = os.environ.get('EVENT_GRID_TOPIC_ENDPOINT') # e.g., "https://<your_event_grid_topic_name>.eastus-1.eventgrid.azure.net/api/events"

# --- Azure SDK Clients (initialized with Managed Identity) ---
# DefaultAzureCredential will automatically use Managed Identity in Azure Function environment
# and fall back to other methods (like environment variables) for local development.
credential = DefaultAzureCredential()

blob_service_client = BlobServiceClient(account_url=BLOB_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_DB_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

# Initialize Cosmos DB database and container (idempotent operations)
try:
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DB_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_DB_CONTAINER_NAME,
        partition_key=PartitionKey(path="/id"), # Use id as partition key for simplicity
        offer_throughput=400
    )
    logging.info(f"Cosmos DB container '{COSMOS_DB_CONTAINER_NAME}' ensured.")
except Exception as e:
    logging.error(f"Error initializing Cosmos DB: {e}")
    # Re-raise to ensure function doesn't start if Cosmos DB setup fails
    raise

app = func.FunctionApp()

@app.blob_trigger(
    arg_name="inputblob",
    path=f"{BLOB_CONTAINER_NAME}/{{name}}",
    connection="AzureWebJobsStorage" # This connection string is used by the trigger itself for the lease/checkpoint container, but the BlobServiceClient above uses Managed Identity for actual data operations.
)
def process_blob_function(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob\n"
                 f"Name: {inputblob.name}\n"
                 f"Blob Size: {inputblob.length} Bytes")

    try:
        # Extract file name
        blob_name = inputblob.name.split('/')[-1]
        file_extension = os.path.splitext(blob_name)[1]

        # Read blob content
        file_content = inputblob.read().decode('utf-8') # Assuming text files for simplicity

        # --- Process File (MVP Logic) ---
        # For an MVP, this could be as simple as counting words, lines, or just storing content.
        processed_data = {
            "id": blob_name, # Use blob name as unique ID for Cosmos DB
            "blobName": blob_name,
            "containerName": BLOB_CONTAINER_NAME,
            "filePath": inputblob.name,
            "fileSize": inputblob.length,
            "fileExtension": file_extension,
            "processedTimestamp": func.get_context().current_utc_datetime.isoformat(),
            "contentPreview": file_content[:200] + "..." if len(file_content) > 200 else file_content,
            "lineCount": file_content.count('\n') + 1 if file_content else 0,
            "wordCount": len(file_content.split()) if file_content else 0
        }
        logging.info(f"File '{blob_name}' processed. Data: {processed_data}")

        # --- Write Results to Cosmos DB ---
        cosmos_container = database.get_container_client(COSMOS_DB_CONTAINER_NAME)
        cosmos_container.upsert_item(body=processed_data)
        logging.info(f"Results for '{blob_name}' upserted to Cosmos DB.")

        # --- Send Notification via Event Grid ---
        event_data = {
            "blobName": blob_name,
            "filePath": inputblob.name,
            "fileSize": inputblob.length,
            "cosmosDbItemId": blob_name,
            "status": "ProcessedSuccessfully",
            "processingTimestamp": processed_data["processedTimestamp"]
        }
        event = CloudEvent(
            type="File.Processed",
            source=f"/azure/storageaccounts/{BLOB_ACCOUNT_URL.split('//')[1].split('.')[0]}/containers/{BLOB_CONTAINER_NAME}",
            data=event_data,
            id=f"file-processed-{blob_name}-{processed_data['processedTimestamp']}",
            datacontenttype="application/json"
        )
        event_grid_client.send(event)
        logging.info(f"Event Grid notification sent for '{blob_name}'.")

    except Exception as e:
        logging.error(f"Error processing blob '{inputblob.name}': {e}")
        # Optionally, send a failure notification to Event Grid
        error_event_data = {
            "blobName": blob_name if 'blob_name' in locals() else "unknown",
            "filePath": inputblob.name,
            "status": "ProcessingFailed",
            "errorMessage": str(e),
            "processingTimestamp": func.get_context().current_utc_datetime.isoformat()
        }
        error_event = CloudEvent(
            type="File.ProcessingFailed",
            source=f"/azure/storageaccounts/{BLOB_ACCOUNT_URL.split('//')[1].split('.')[0]}/containers/{BLOB_CONTAINER_NAME}",
            data=error_event_data,
            id=f"file-failed-{blob_name if 'blob_name' in locals() else 'unknown'}-{error_event_data['processingTimestamp']}",
            datacontenttype="application/json"
        )
        event_grid_client.send(error_event)
        logging.info(f"Error Event Grid notification sent for '{inputblob.name}'.")